import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const BusManagerDashboard = () => {
  const [manager, setManager] = useState(null);
  const [buses, setBuses] = useState([]);
  const [todayBookings, setTodayBookings] = useState([]);
  const [revenue, setRevenue] = useState(0);
  const navigate = useNavigate();

  useEffect(() => {
    const managerData = localStorage.getItem('user');
    if (managerData) {
      setManager(JSON.parse(managerData));
      loadDashboardData();
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const loadDashboardData = () => {
    // Mock buses data
    const mockBuses = [
      {
        id: 1,
        busNumber: 'BUS-001',
        busName: 'Express Travels',
        busType: 'AC Sleeper',
        route: 'New York → Los Angeles',
        status: 'Active',
        totalSeats: 40,
        availableSeats: 12,
        driverName: 'John Smith',
        driverContact: '+1-234-567-8900'
      },
      {
        id: 2,
        busNumber: 'BUS-002',
        busName: 'Royal Bus Service',
        busType: 'Non AC Seater',
        route: 'Chicago → Houston',
        status: 'Active',
        totalSeats: 45,
        availableSeats: 8,
        driverName: 'Mike Johnson',
        driverContact: '+1-234-567-8901'
      },
      {
        id: 3,
        busNumber: 'BUS-003',
        busName: 'Super Deluxe',
        busType: 'AC Seater',
        route: 'Philadelphia → Phoenix',
        status: 'Maintenance',
        totalSeats: 35,
        availableSeats: 0,
        driverName: 'Robert Brown',
        driverContact: '+1-234-567-8902'
      }
    ];
    setBuses(mockBuses);

    // Mock today's bookings
    const mockBookings = [
      {
        id: 'BK123456',
        busName: 'Express Travels',
        route: 'New York → Los Angeles',
        departure: '08:00 AM',
        seats: ['12', '13'],
        amount: 900,
        status: 'Confirmed',
        passengerName: 'Alice Johnson'
      },
      {
        id: 'BK789012',
        busName: 'Royal Bus Service',
        route: 'Chicago → Houston',
        departure: '10:30 AM',
        seats: ['5'],
        amount: 280,
        status: 'Confirmed',
        passengerName: 'Bob Smith'
      }
    ];
    setTodayBookings(mockBookings);

    // Calculate revenue
    const totalRevenue = mockBookings.reduce((sum, booking) => sum + booking.amount, 0);
    setRevenue(totalRevenue);
  };

  const handleAddBus = () => {
    navigate('/bus-manager/add-bus');
  };

  const handleEditBus = (busId) => {
    navigate(`/bus-manager/edit-bus/${busId}`);
  };

  const handleViewBookings = (busId) => {
    navigate(`/bus-manager/bookings/${busId}`);
  };

  const handleTrackBus = (busId) => {
    navigate(`/track-bus-manager/${busId}`);
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'Active': return '#28a745';
      case 'Maintenance': return '#ffc107';
      case 'Inactive': return '#dc3545';
      default: return '#6c757d';
    }
  };

  const getOccupancyRate = (totalSeats, availableSeats) => {
    const occupied = totalSeats - availableSeats;
    return Math.round((occupied / totalSeats) * 100);
  };

  if (!manager) {
    return <div>Loading...</div>;
  }

  return (
    <div className="container">
      <div className="card">
        <h2>Welcome, {manager.name}!</h2>
        <p style={{ color: '#666' }}>Manage your bus fleet and operations</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px', marginBottom: '30px' }}>
        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#007bff', marginBottom: '10px' }}>🚌 Total Buses</h3>
          <div style={{ fontSize: '36px', fontWeight: 'bold', color: '#007bff', marginBottom: '10px' }}>
            {buses.length}
          </div>
          <button className="btn btn-secondary" onClick={handleAddBus} style={{ marginTop: '10px' }}>
            Add New Bus
          </button>
        </div>

        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#28a745', marginBottom: '10px' }}>📅 Today's Bookings</h3>
          <div style={{ fontSize: '36px', fontWeight: 'bold', color: '#28a745', marginBottom: '10px' }}>
            {todayBookings.length}
          </div>
          <button className="btn btn-secondary" onClick={() => navigate('/bus-manager/all-bookings')}>
            View All
          </button>
        </div>

        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#ffc107', marginBottom: '10px' }}>💰 Today's Revenue</h3>
          <div style={{ fontSize: '36px', fontWeight: 'bold', color: '#ffc107', marginBottom: '10px' }}>
            ₹{revenue}
          </div>
          <button className="btn btn-secondary" onClick={() => navigate('/bus-manager/reports')}>
            View Reports
          </button>
        </div>

        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#dc3545', marginBottom: '10px' }}>⚠️ Maintenance</h3>
          <div style={{ fontSize: '36px', fontWeight: 'bold', color: '#dc3545', marginBottom: '10px' }}>
            {buses.filter(b => b.status === 'Maintenance').length}
          </div>
          <button className="btn btn-secondary" onClick={() => navigate('/bus-manager/maintenance')}>
            Manage
          </button>
        </div>
      </div>

      <div className="card">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h3>Your Bus Fleet</h3>
          <button className="btn" onClick={handleAddBus}>
            + Add New Bus
          </button>
        </div>

        {buses.length === 0 ? (
          <p>No buses in your fleet. Add your first bus to get started!</p>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {buses.map(bus => (
              <div key={bus.id} className="card" style={{ border: '1px solid #ddd' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1fr auto', gap: '20px', alignItems: 'center' }}>
                  <div>
                    <h4 style={{ margin: '0 0 5px 0' }}>{bus.busName}</h4>
                    <p style={{ margin: '0', color: '#666', fontSize: '14px' }}>
                      {bus.busNumber} | {bus.busType}
                    </p>
                    <p style={{ margin: '5px 0 0 0', fontSize: '12px', color: '#666' }}>
                      {bus.route} | Driver: {bus.driverName}
                    </p>
                  </div>

                  <div>
                    <div style={{ 
                      padding: '4px 8px', 
                      borderRadius: '4px', 
                      backgroundColor: getStatusColor(bus.status),
                      color: 'white',
                      fontSize: '12px',
                      fontWeight: 'bold',
                      textAlign: 'center'
                    }}>
                      {bus.status}
                    </div>
                  </div>

                  <div>
                    <div style={{ fontSize: '14px', fontWeight: 'bold' }}>
                      {bus.availableSeats}/{bus.totalSeats}
                    </div>
                    <div style={{ fontSize: '12px', color: '#666' }}>
                      {getOccupancyRate(bus.totalSeats, bus.availableSeats)}% Occupied
                    </div>
                  </div>

                  <div>
                    <div style={{ fontSize: '12px', color: '#666' }}>
                      📞 {bus.driverContact}
                    </div>
                  </div>

                  <div>
                    <div style={{ display: 'flex', gap: '5px', flexDirection: 'column' }}>
                      <button
                        className="btn btn-secondary"
                        onClick={() => handleEditBus(bus.id)}
                        style={{ padding: '5px 10px', fontSize: '12px' }}
                      >
                        Edit
                      </button>
                      <button
                        className="btn btn-secondary"
                        onClick={() => handleViewBookings(bus.id)}
                        style={{ padding: '5px 10px', fontSize: '12px' }}
                      >
                        Bookings
                      </button>
                      {bus.status === 'Active' && (
                        <button
                          className="btn"
                          onClick={() => handleTrackBus(bus.id)}
                          style={{ padding: '5px 10px', fontSize: '12px' }}
                        >
                          Track
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="card">
        <h3>Today's Bookings</h3>
        {todayBookings.length === 0 ? (
          <p>No bookings for today.</p>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {todayBookings.map(booking => (
              <div key={booking.id} style={{ 
                display: 'flex', 
                justifyContent: 'space-between', 
                alignItems: 'center',
                padding: '10px',
                backgroundColor: '#f8f9fa',
                borderRadius: '5px'
              }}>
                <div>
                  <strong>{booking.busName}</strong> - {booking.route}
                  <div style={{ fontSize: '12px', color: '#666' }}>
                    {booking.departure} | Seats: {booking.seats.join(', ')} | {booking.passengerName}
                  </div>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <div style={{ fontWeight: 'bold', color: '#007bff' }}>₹{booking.amount}</div>
                  <div style={{ fontSize: '12px', color: '#666' }}>{booking.id}</div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default BusManagerDashboard;
